import{_ as a,c as o,o as r,aj as t}from"./chunks/framework.BlveriQe.js";const u=JSON.parse('{"title":"Interface: DocumentContext","description":"","frontmatter":{},"headers":[],"relativePath":"reference/js-bao-wss-client/api/interfaces/DocumentContext.md","filePath":"reference/js-bao-wss-client/api/interfaces/DocumentContext.md"}'),n={name:"reference/js-bao-wss-client/api/interfaces/DocumentContext.md"};function s(d,e,c,i,l,h){return r(),o("div",null,[...e[0]||(e[0]=[t('<p><a href="./../README.html"><strong>js-bao-wss-client</strong></a></p><hr><p><a href="./../globals.html">js-bao-wss-client</a> / DocumentContext</p><h1 id="interface-documentcontext" tabindex="-1">Interface: DocumentContext <a class="header-anchor" href="#interface-documentcontext" aria-label="Permalink to “Interface: DocumentContext”">​</a></h1><p>Scoped API for operating on a single document without repeating the document ID.</p><h2 id="methods" tabindex="-1">Methods <a class="header-anchor" href="#methods" aria-label="Permalink to “Methods”">​</a></h2><h3 id="acceptinvitation" tabindex="-1"><s>acceptInvitation()</s> <a class="header-anchor" href="#acceptinvitation" aria-label="Permalink to “acceptInvitation()”">​</a></h3><blockquote><p><strong>acceptInvitation</strong>(): <code>Promise</code>&lt;<a href="./DocumentAccessResult.html"><code>DocumentAccessResult</code></a>&gt;</p></blockquote><p>Accept a pending invitation to access this document.</p><h4 id="returns" tabindex="-1">Returns <a class="header-anchor" href="#returns" aria-label="Permalink to “Returns”">​</a></h4><p><code>Promise</code>&lt;<a href="./DocumentAccessResult.html"><code>DocumentAccessResult</code></a>&gt;</p><h4 id="deprecated" tabindex="-1">Deprecated <a class="header-anchor" href="#deprecated" aria-label="Permalink to “Deprecated”">​</a></h4><p>The per-document accept concept has been removed. Document shares to existing users take effect immediately via <code>documents.updatePermissions</code> — no accept call is needed. For not-yet-registered users, deferred grants resolve when the recipient accepts the app-level invitation via <code>client.invitations.accept(inviteToken)</code>. The <code>inviteToken</code> is provided in the deferred-grant response of <code>documents.updatePermissions</code> on the inviter side, not via any invitee-callable on <code>documents.*</code>. See issue #619 and <a href="./DocumentsAPI.html#acceptinvitation">DocumentsAPI.acceptInvitation</a>.</p><hr><h3 id="blobs" tabindex="-1">blobs() <a class="header-anchor" href="#blobs" aria-label="Permalink to “blobs()”">​</a></h3><blockquote><p><strong>blobs</strong>(): <a href="./DocumentBlobContext.html"><code>DocumentBlobContext</code></a></p></blockquote><p>Get the blob API context for this document.</p><h4 id="returns-1" tabindex="-1">Returns <a class="header-anchor" href="#returns-1" aria-label="Permalink to “Returns”">​</a></h4><p><a href="./DocumentBlobContext.html"><code>DocumentBlobContext</code></a></p><hr><h3 id="declineinvitation" tabindex="-1"><s>declineInvitation()</s> <a class="header-anchor" href="#declineinvitation" aria-label="Permalink to “declineInvitation()”">​</a></h3><blockquote><p><strong>declineInvitation</strong>(<code>invitationId</code>): <code>Promise</code>&lt;{ <code>message</code>: <code>string</code>; <code>success</code>: <code>boolean</code>; }&gt;</p></blockquote><p>Decline a pending invitation to access this document.</p><h4 id="parameters" tabindex="-1">Parameters <a class="header-anchor" href="#parameters" aria-label="Permalink to “Parameters”">​</a></h4><h5 id="invitationid" tabindex="-1">invitationId <a class="header-anchor" href="#invitationid" aria-label="Permalink to “invitationId”">​</a></h5><p><code>string</code></p><p>The identifier of the specific invitation to decline</p><h4 id="returns-2" tabindex="-1">Returns <a class="header-anchor" href="#returns-2" aria-label="Permalink to “Returns”">​</a></h4><p><code>Promise</code>&lt;{ <code>message</code>: <code>string</code>; <code>success</code>: <code>boolean</code>; }&gt;</p><h4 id="deprecated-1" tabindex="-1">Deprecated <a class="header-anchor" href="#deprecated-1" aria-label="Permalink to “Deprecated”">​</a></h4><p>No invitee-side decline verb. Pending invitations expire automatically, so a recipient who hasn&#39;t accepted can simply ignore the invite. To remove yourself from an already-accepted share, call <code>documents.removePermission(documentId, { userId: &lt;your userId&gt; })</code>. See issue #619 and <a href="./DocumentsAPI.html#declineinvitation">DocumentsAPI.declineInvitation</a>.</p><hr><h3 id="delete" tabindex="-1">delete() <a class="header-anchor" href="#delete" aria-label="Permalink to “delete()”">​</a></h3><blockquote><p><strong>delete</strong>(<code>options?</code>): <code>Promise</code>&lt;<code>void</code>&gt;</p></blockquote><p>Delete this document from the server and evict its local data.</p><h4 id="parameters-1" tabindex="-1">Parameters <a class="header-anchor" href="#parameters-1" aria-label="Permalink to “Parameters”">​</a></h4><h5 id="options" tabindex="-1">options? <a class="header-anchor" href="#options" aria-label="Permalink to “options?”">​</a></h5><p><code>DeleteDocumentOptions</code></p><p>Options for document deletion</p><h4 id="returns-3" tabindex="-1">Returns <a class="header-anchor" href="#returns-3" aria-label="Permalink to “Returns”">​</a></h4><p><code>Promise</code>&lt;<code>void</code>&gt;</p><hr><h3 id="get" tabindex="-1">get() <a class="header-anchor" href="#get" aria-label="Permalink to “get()”">​</a></h3><blockquote><p><strong>get</strong>(): <code>Promise</code>&lt;<a href="./DocumentInfo.html"><code>DocumentInfo</code></a>&gt;</p></blockquote><p>Fetch this document&#39;s metadata from the server.</p><h4 id="returns-4" tabindex="-1">Returns <a class="header-anchor" href="#returns-4" aria-label="Permalink to “Returns”">​</a></h4><p><code>Promise</code>&lt;<a href="./DocumentInfo.html"><code>DocumentInfo</code></a>&gt;</p><hr><h3 id="getlocalmetadata" tabindex="-1">getLocalMetadata() <a class="header-anchor" href="#getlocalmetadata" aria-label="Permalink to “getLocalMetadata()”">​</a></h3><blockquote><p><strong>getLocalMetadata</strong>(): <code>Promise</code>&lt;<code>LocalMetadataEntry</code> | <code>null</code>&gt;</p></blockquote><p>Get locally cached metadata for this document.</p><h4 id="returns-5" tabindex="-1">Returns <a class="header-anchor" href="#returns-5" aria-label="Permalink to “Returns”">​</a></h4><p><code>Promise</code>&lt;<code>LocalMetadataEntry</code> | <code>null</code>&gt;</p><hr><h3 id="getpermissions" tabindex="-1">getPermissions() <a class="header-anchor" href="#getpermissions" aria-label="Permalink to “getPermissions()”">​</a></h3><blockquote><p><strong>getPermissions</strong>(): <code>Promise</code>&lt;<a href="./DocumentPermissionEntry.html"><code>DocumentPermissionEntry</code></a>[]&gt;</p></blockquote><p>Get the list of user permissions for this document.</p><h4 id="returns-6" tabindex="-1">Returns <a class="header-anchor" href="#returns-6" aria-label="Permalink to “Returns”">​</a></h4><p><code>Promise</code>&lt;<a href="./DocumentPermissionEntry.html"><code>DocumentPermissionEntry</code></a>[]&gt;</p><hr><h3 id="getuploadconcurrency" tabindex="-1">getUploadConcurrency() <a class="header-anchor" href="#getuploadconcurrency" aria-label="Permalink to “getUploadConcurrency()”">​</a></h3><blockquote><p><strong>getUploadConcurrency</strong>(): <code>number</code></p></blockquote><p>Get the current maximum number of concurrent blob uploads.</p><h4 id="returns-7" tabindex="-1">Returns <a class="header-anchor" href="#returns-7" aria-label="Permalink to “Returns”">​</a></h4><p><code>number</code></p><hr><h3 id="grantgrouppermission" tabindex="-1">grantGroupPermission() <a class="header-anchor" href="#grantgrouppermission" aria-label="Permalink to “grantGroupPermission()”">​</a></h3><blockquote><p><strong>grantGroupPermission</strong>(<code>params</code>): <code>Promise</code>&lt;<a href="./DocumentGroupPermissionEntry.html"><code>DocumentGroupPermissionEntry</code></a>&gt;</p></blockquote><p>Grant a group permission on this document.</p><h4 id="parameters-2" tabindex="-1">Parameters <a class="header-anchor" href="#parameters-2" aria-label="Permalink to “Parameters”">​</a></h4><h5 id="params" tabindex="-1">params <a class="header-anchor" href="#params" aria-label="Permalink to “params”">​</a></h5><p><code>GrantGroupPermissionParams</code></p><p>The group permission to grant</p><h4 id="returns-8" tabindex="-1">Returns <a class="header-anchor" href="#returns-8" aria-label="Permalink to “Returns”">​</a></h4><p><code>Promise</code>&lt;<a href="./DocumentGroupPermissionEntry.html"><code>DocumentGroupPermissionEntry</code></a>&gt;</p><hr><h3 id="isreadonly" tabindex="-1">isReadOnly() <a class="header-anchor" href="#isreadonly" aria-label="Permalink to “isReadOnly()”">​</a></h3><blockquote><p><strong>isReadOnly</strong>(): <code>boolean</code></p></blockquote><p>Check whether this document is read-only for the current user.</p><h4 id="returns-9" tabindex="-1">Returns <a class="header-anchor" href="#returns-9" aria-label="Permalink to “Returns”">​</a></h4><p><code>boolean</code></p><hr><h3 id="isroot" tabindex="-1">isRoot() <a class="header-anchor" href="#isroot" aria-label="Permalink to “isRoot()”">​</a></h3><blockquote><p><strong>isRoot</strong>(): <code>boolean</code></p></blockquote><p>Check whether this document is the app&#39;s root document.</p><h4 id="returns-10" tabindex="-1">Returns <a class="header-anchor" href="#returns-10" aria-label="Permalink to “Returns”">​</a></h4><p><code>boolean</code></p><hr><h3 id="listgrouppermissions" tabindex="-1">listGroupPermissions() <a class="header-anchor" href="#listgrouppermissions" aria-label="Permalink to “listGroupPermissions()”">​</a></h3><blockquote><p><strong>listGroupPermissions</strong>(<code>options?</code>): <code>Promise</code>&lt;<a href="./DocumentGroupPermissionEntry.html"><code>DocumentGroupPermissionEntry</code></a>[]&gt;</p></blockquote><p>List all group-based permissions for this document.</p><p>By default, platform-managed internal groups (<code>groupType</code> prefixed with <code>_</code>) are excluded. Pass <code>{ includeSystem: true }</code> to include them.</p><h4 id="parameters-3" tabindex="-1">Parameters <a class="header-anchor" href="#parameters-3" aria-label="Permalink to “Parameters”">​</a></h4><h5 id="options-1" tabindex="-1">options? <a class="header-anchor" href="#options-1" aria-label="Permalink to “options?”">​</a></h5><h6 id="includesystem" tabindex="-1">includeSystem? <a class="header-anchor" href="#includesystem" aria-label="Permalink to “includeSystem?”">​</a></h6><p><code>boolean</code></p><h4 id="returns-11" tabindex="-1">Returns <a class="header-anchor" href="#returns-11" aria-label="Permalink to “Returns”">​</a></h4><p><code>Promise</code>&lt;<a href="./DocumentGroupPermissionEntry.html"><code>DocumentGroupPermissionEntry</code></a>[]&gt;</p><hr><h3 id="pausealluploads" tabindex="-1">pauseAllUploads() <a class="header-anchor" href="#pausealluploads" aria-label="Permalink to “pauseAllUploads()”">​</a></h3><blockquote><p><strong>pauseAllUploads</strong>(): <code>void</code></p></blockquote><p>Pause all blob uploads for this document.</p><h4 id="returns-12" tabindex="-1">Returns <a class="header-anchor" href="#returns-12" aria-label="Permalink to “Returns”">​</a></h4><p><code>void</code></p><hr><h3 id="pauseupload" tabindex="-1">pauseUpload() <a class="header-anchor" href="#pauseupload" aria-label="Permalink to “pauseUpload()”">​</a></h3><blockquote><p><strong>pauseUpload</strong>(<code>blobId</code>): <code>boolean</code></p></blockquote><p>Pause a specific blob upload for this document.</p><h4 id="parameters-4" tabindex="-1">Parameters <a class="header-anchor" href="#parameters-4" aria-label="Permalink to “Parameters”">​</a></h4><h5 id="blobid" tabindex="-1">blobId <a class="header-anchor" href="#blobid" aria-label="Permalink to “blobId”">​</a></h5><p><code>string</code></p><p>The identifier of the blob upload to pause</p><h4 id="returns-13" tabindex="-1">Returns <a class="header-anchor" href="#returns-13" aria-label="Permalink to “Returns”">​</a></h4><p><code>boolean</code></p><hr><h3 id="resumealluploads" tabindex="-1">resumeAllUploads() <a class="header-anchor" href="#resumealluploads" aria-label="Permalink to “resumeAllUploads()”">​</a></h3><blockquote><p><strong>resumeAllUploads</strong>(): <code>void</code></p></blockquote><p>Resume all paused blob uploads for this document.</p><h4 id="returns-14" tabindex="-1">Returns <a class="header-anchor" href="#returns-14" aria-label="Permalink to “Returns”">​</a></h4><p><code>void</code></p><hr><h3 id="resumeupload" tabindex="-1">resumeUpload() <a class="header-anchor" href="#resumeupload" aria-label="Permalink to “resumeUpload()”">​</a></h3><blockquote><p><strong>resumeUpload</strong>(<code>blobId</code>): <code>boolean</code></p></blockquote><p>Resume a specific paused blob upload for this document.</p><h4 id="parameters-5" tabindex="-1">Parameters <a class="header-anchor" href="#parameters-5" aria-label="Permalink to “Parameters”">​</a></h4><h5 id="blobid-1" tabindex="-1">blobId <a class="header-anchor" href="#blobid-1" aria-label="Permalink to “blobId”">​</a></h5><p><code>string</code></p><p>The identifier of the paused blob upload to resume</p><h4 id="returns-15" tabindex="-1">Returns <a class="header-anchor" href="#returns-15" aria-label="Permalink to “Returns”">​</a></h4><p><code>boolean</code></p><hr><h3 id="revokegrouppermission" tabindex="-1">revokeGroupPermission() <a class="header-anchor" href="#revokegrouppermission" aria-label="Permalink to “revokeGroupPermission()”">​</a></h3><blockquote><p><strong>revokeGroupPermission</strong>(<code>groupType</code>, <code>groupId</code>): <code>Promise</code>&lt;{ <code>success</code>: <code>boolean</code>; }&gt;</p></blockquote><p>Revoke a group&#39;s permission on this document.</p><h4 id="parameters-6" tabindex="-1">Parameters <a class="header-anchor" href="#parameters-6" aria-label="Permalink to “Parameters”">​</a></h4><h5 id="grouptype" tabindex="-1">groupType <a class="header-anchor" href="#grouptype" aria-label="Permalink to “groupType”">​</a></h5><p><code>string</code></p><p>The type of group whose permission to revoke</p><h5 id="groupid" tabindex="-1">groupId <a class="header-anchor" href="#groupid" aria-label="Permalink to “groupId”">​</a></h5><p><code>string</code></p><p>The identifier of the group whose permission to revoke</p><h4 id="returns-16" tabindex="-1">Returns <a class="header-anchor" href="#returns-16" aria-label="Permalink to “Returns”">​</a></h4><p><code>Promise</code>&lt;{ <code>success</code>: <code>boolean</code>; }&gt;</p><hr><h3 id="setuploadconcurrency" tabindex="-1">setUploadConcurrency() <a class="header-anchor" href="#setuploadconcurrency" aria-label="Permalink to “setUploadConcurrency()”">​</a></h3><blockquote><p><strong>setUploadConcurrency</strong>(<code>concurrency</code>): <code>void</code></p></blockquote><p>Set the maximum number of concurrent blob uploads.</p><h4 id="parameters-7" tabindex="-1">Parameters <a class="header-anchor" href="#parameters-7" aria-label="Permalink to “Parameters”">​</a></h4><h5 id="concurrency" tabindex="-1">concurrency <a class="header-anchor" href="#concurrency" aria-label="Permalink to “concurrency”">​</a></h5><p><code>number</code></p><p>The maximum number of blob uploads that can run simultaneously</p><h4 id="returns-17" tabindex="-1">Returns <a class="header-anchor" href="#returns-17" aria-label="Permalink to “Returns”">​</a></h4><p><code>void</code></p><hr><h3 id="transferownership" tabindex="-1">transferOwnership() <a class="header-anchor" href="#transferownership" aria-label="Permalink to “transferOwnership()”">​</a></h3><blockquote><p><strong>transferOwnership</strong>(<code>newOwnerId</code>): <code>Promise</code>&lt;<code>void</code>&gt;</p></blockquote><p>Transfer ownership of this document to another user.</p><h4 id="parameters-8" tabindex="-1">Parameters <a class="header-anchor" href="#parameters-8" aria-label="Permalink to “Parameters”">​</a></h4><h5 id="newownerid" tabindex="-1">newOwnerId <a class="header-anchor" href="#newownerid" aria-label="Permalink to “newOwnerId”">​</a></h5><p><code>string</code></p><p>The user ID of the new owner</p><h4 id="returns-18" tabindex="-1">Returns <a class="header-anchor" href="#returns-18" aria-label="Permalink to “Returns”">​</a></h4><p><code>Promise</code>&lt;<code>void</code>&gt;</p><hr><h3 id="update" tabindex="-1">update() <a class="header-anchor" href="#update" aria-label="Permalink to “update()”">​</a></h3><blockquote><p><strong>update</strong>(<code>data</code>): <code>Promise</code>&lt;<a href="./DocumentInfo.html"><code>DocumentInfo</code></a>&gt;</p></blockquote><p>Update this document&#39;s metadata such as its title.</p><h4 id="parameters-9" tabindex="-1">Parameters <a class="header-anchor" href="#parameters-9" aria-label="Permalink to “Parameters”">​</a></h4><h5 id="data" tabindex="-1">data <a class="header-anchor" href="#data" aria-label="Permalink to “data”">​</a></h5><p><code>UpdateDocumentData</code></p><p>The document metadata fields to update</p><h4 id="returns-19" tabindex="-1">Returns <a class="header-anchor" href="#returns-19" aria-label="Permalink to “Returns”">​</a></h4><p><code>Promise</code>&lt;<a href="./DocumentInfo.html"><code>DocumentInfo</code></a>&gt;</p><hr><h3 id="uploads" tabindex="-1">uploads() <a class="header-anchor" href="#uploads" aria-label="Permalink to “uploads()”">​</a></h3><blockquote><p><strong>uploads</strong>(): <a href="./BlobUploadStatus.html"><code>BlobUploadStatus</code></a>[]</p></blockquote><p>List active blob uploads for this document.</p><h4 id="returns-20" tabindex="-1">Returns <a class="header-anchor" href="#returns-20" aria-label="Permalink to “Returns”">​</a></h4><p><a href="./BlobUploadStatus.html"><code>BlobUploadStatus</code></a>[]</p>',179)])])}const m=a(n,[["render",s]]);export{u as __pageData,m as default};
